package com.sensitivity.converter;

import javax.swing.*;
import java.awt.*;
import java.awt.image.BufferedImage;
import java.io.ByteArrayInputStream;
import java.util.Base64;
import javax.imageio.ImageIO;

public class GameIconManager {
    
    // Game icons as base64 encoded PNG data
    private static final String VALORANT_ICON = "";
    
    private static final String ROBLOX_ICON = "";
    
    private static final String CS2_ICON = "";
    
    private static final String CROSSFIRE_ICON = "";
    
    private static final String OVERWATCH_ICON = "";
    
    private static final String APEX_LEGENDS_ICON = "";
    
    private static final String FORTNITE_ICON = "";
    
    /**
     * Get ImageIcon for a specific game
     */
    public static ImageIcon getGameIcon(String gameName) {
        String base64Data = null;
        
        switch(gameName.toLowerCase()) {
            case "valorant":
                base64Data = VALORANT_ICON;
                break;
            case "roblox":
                base64Data = ROBLOX_ICON;
                break;
            case "cs2":
                base64Data = CS2_ICON;
                break;
            case "crossfire":
                base64Data = CROSSFIRE_ICON;
                break;
            case "overwatch":
                base64Data = OVERWATCH_ICON;
                break;
            case "apex legends":
                base64Data = APEX_LEGENDS_ICON;
                break;
            case "fortnite":
                base64Data = FORTNITE_ICON;
                break;
            default:
                return null;
        }
        
        try {
            if (base64Data == null) return null;
            
            byte[] decodedBytes = Base64.getDecoder().decode(base64Data);
            BufferedImage image = ImageIO.read(new ByteArrayInputStream(decodedBytes));
            
            // Scale to 30x30
            Image scaledImage = image.getScaledInstance(30, 30, Image.SCALE_SMOOTH);
            return new ImageIcon(scaledImage);
        } catch (Exception e) {
            e.printStackTrace();
            return null;
        }
    }
}
